"use strict";(self.webpackChunkcarrgan_io=self.webpackChunkcarrgan_io||[]).push([[1477],{10:function(e){e.exports=JSON.parse('{"blogPosts":[{"id":"process-env-node-env","metadata":{"permalink":"/blog/process-env-node-env","source":"@site/blog/2022-04-01-\u524d\u7aef\u7684\u73af\u5883\u53d8\u91cf/index.md","title":"\u524d\u7aef\u7684\u73af\u5883\u53d8\u91cf","description":"Process Env","date":"2022-04-01T00:00:00.000Z","formattedDate":"2022\u5e744\u67081\u65e5","tags":[{"label":"Front-End","permalink":"/blog/tags/front-end"}],"readingTime":1.604,"truncated":false,"authors":[{"name":"Carrgan Yang","title":"Software Engineer @ Ericsson","url":"https://github.com/carrgan","imageURL":"https://carrgan.github.io/img/avantar/carrgan.jpg","key":"carrgan"}],"frontMatter":{"slug":"process-env-node-env","title":"\u524d\u7aef\u7684\u73af\u5883\u53d8\u91cf","authors":"carrgan","tags":["Front-End"]},"nextItem":{"title":"CSS\u81ea\u9002\u5e94\u56fa\u5b9a\u957f\u6b3e\u6bd4\u5bb9\u5668","permalink":"/blog/dynamic-height-container"}},"content":"## Process Env\\n\\n\u5728\u6b63\u5e38\u7684\u5f00\u53d1\u6d41\u7a0b\u4e2d\uff0c\u901a\u5e38\u4f1a\u7ecf\u5386Development/Acceptance(Test)/Production\u9636\u6bb5\uff0c\u53ef\u80fd\u4f60\u4f1a\u60f3\u5728\u4e0d\u540c\u7684\u73af\u5883\u505a\u4e0d\u540c\u7684\u4e8b\uff0c\u6216\u662f\u7ed9\u540c\u4e00\u4e2a\u53d8\u91cf\u8d4b\u4e0d\u540c\u7684\u503c\u3002\\n\\n\u540e\u7aef\u4ee3\u7801\u83b7\u5f97\u73af\u5883\u53d8\u91cf\u7684\u65b9\u6cd5\u975e\u5e38\u7b80\u5355\uff0c\u53ea\u7528\u5728\u4e0d\u540c\u7684\u73af\u5883\u4e0b\u8bfb\u53d6\u4e0d\u540c\u7684\u914d\u7f6e\u6587\u4ef6\uff0c\u6216\u8005\u662f\u8bfb\u53d6\u64cd\u4f5c\u7cfb\u7edf\u5b9a\u4e49\u7684\u73af\u5883\u53d8\u91cf\u5373\u53ef\u3002\\n\\n\u53ef\u662f\u524d\u7aef\u4ee3\u7801\u662f\u8fd0\u884c\u5728\u6d4f\u89c8\u4e0a\u7684\u6211\u4eec\u5982\u4f55\u53bb\u8bfb\u53d6\u73af\u5883\u53d8\u91cf\u5462\uff1f\\n\\n\u901a\u5e38\u4f7f\u7528\u73b0\u4ee3\u6846\u67b6 (React/Vue) \u7684\u524d\u7aef\u7a0b\u5e8f\u5458\u5728\u5f00\u53d1\u4ee3\u7801\u7684\u65f6\u5019\uff0c\u90fd\u4f1a\u7528\u5230webpack\uff0c\u524d\u7aef\u7684\u73af\u5883\u53d8\u91cf\u5176\u5b9e\u662f\u5728webpack\u6253\u5305\u7684\u65f6\u5019\u88ab\u5b9a\u4e49\u7684\u3002\\n\\n\u901a\u5e38\uff0c\u5728\u6211\u4eec\u542f\u52a8\u5f00\u53d1\u670d\u52a1\u5668\u7684\u65f6\u5019 `npm run start` webpack\u5c06 `process.env.NODE_ENV` \u6253\u5305\u4e3a`development`\uff0c\u800c\u6211\u4eec\u5728\u8fd0\u884c `npm run build` \u7684\u662f\u65f6\u5019 webpack \u628a `process.env.NODE_ENV` \u6253\u5305\u4e3a `production`\u3002\\n\\n:::caution\\n\\n`process`\u5e76\u4e0d\u662f\u4e00\u4e2a\u5bf9\u8c61\uff0c`process.env`\u4e5f\u4e0d\u662f\u4e00\u4e2a\u5bf9\u8c61\uff0c\u5982\u679c\u4f60\u5199\u51fa\u5982\u4e0b\u8bed\u53e5`console.log(process.env)`\u4f60\u4f1a\u5f97\u5230\u4e00\u4e2a`process undefined`\u9519\u8bef\u3002\\n\u4f46\u662f\u4f60\u5199\u51fa`console.log(process.env.NODE_ENV)`\u4f60\u4f1a\u5f97\u5230\u4e00\u4e2a\u5b57\u7b26\u4e32\u3002\u662f\u4ec0\u4e48\u5982\u6b64\u795e\u5668\uff1f\u4e8b\u5b9e\u4e0a\u5728webpack\u6253\u5305\u7684\u65f6\u5019\uff0cwebpack\u81ea\u52a8\u628a`process.env.NODE_ENV`\u66ff\u6362\u6210`\\"development\\"`\u4e86\u3002\\n\\n:::\\n\\n## Config.js\\n\\n\u4f8b\u7528\u4ee5\u4e0a\u7279\u6027\u5c31\u53ef\u4ee5\u5b9e\u73b0\u5728\u5f00\u53d1\u7684\u65f6\u5019\u548c\u6253\u5305\u4e4b\u540e\u8fd0\u884c\u4e0d\u540c\u7684\u4ee3\u7801\u6216\u8005\u7ed9\u540c\u4e00\u4e2a\u53d8\u91cf\u8d4b\u4e0d\u540c\u7684\u503c\\n\\n```ts\\nconst config = process.env.NODE_ENV === \\"developemt\\" ? DEV_CONFIG : PROD_CONFIG;\\nprocess.env.NODE_ENV === \\"developemt\\" ? funcDev(): funcProd();\\n```\\n\\n\u4f46\u662f\u8fd9\u8fdc\u8fdc\u8fd8\u4e0d\u591f\uff0c\u5728\u4e00\u4e2a\u5927\u7684\u5f00\u53d1\u56e2\u961f\u4e2d\uff0c\u4e09\u4e2a\u73af\u5883\u90fd\u9700\u8981\u6253\u5305\uff0c\u5e76\u8fd0\u884c\u5728\u4e0d\u540c\u7684\u673a\u5668\u4e0a\u8fdb\u884c\uff0c\u8fd9\u79cd\u60c5\u51b5\u4e0b\u5982\u4f55\u914d\u7f6e\u4e0d\u540c\u7684\u53d8\u91cf\u5462\uff1f\\n\\n\u6211\u4eec\u53ef\u4ee5\u5728public\u6587\u4ef6\u5939\u4e0b\u521b\u5efa\u4e00\u4e2a\u914d\u7f6e\u6587\u4ef6\\n\\n```js title=\\"public/runtime-config.js\\"\\nwindow[config] = {\\n  clintId: \\"xxxx\\"\\n}\\n```\\n\\n```html title=\\"public/index.html\\"\\n<html>\\n<head>\\n  <script src=\\"%PUBLIC_URL%/runtime-config.js\\"><\/script>\\n</head>\\n</html>\\n```\\n\\n```ts title=\\"Any File\\"\\nconst clintId = (window as any).config.clintId;\\n```\\n\\npublic/runtime-config.js \u5728\u6253\u5305\u4e4b\u540e\u4f1a\u88ab\u653e\u5230\u6253\u5305\u6587\u4ef6\u7684\u8ddf\u76ee\u5f55\u4e0b\uff0c\u800c\u5199\u5728\u5934\u91cc\u7684script\u4f1a\u4f18\u5148\u8fd0\u884c\u6211\u4eec\u7684config\u6587\u4ef6\uff0c\u5c06\u6211\u4eec\u7684config\u5bf9\u8c61\u6302\u5230window\u4e0a\uff0c\u8fd9\u6837\u540e\u7eed\u7684\u4ee3\u7801\u5c31\u80fd\u62ff\u5230config\u5bf9\u8c61\u7684\u4e86\u3002\\n\\n\u6211\u4eec\u53ea\u9700\u8981\u53bb\u5230\u4e0d\u540c\u673a\u5668\u4e0a\u4fee\u6539runtime-config.js\u5c31\u53ef\u4ee5\u5bf9\u4e0d\u540c\u7684\u73af\u5883\u5e94\u7528\u4e0d\u540c\u7684\u53d8\u91cf\u4e86\u3002\\n\\n## CI/CD\\n\\n\u5f53\u7136\u5728\u8fd0\u7528CI/CD\u7684\u9879\u76ee\u4e2d\u6211\u4eec\u5c31\u53ef\u4ee5\u7701\u53bb\u624b\u52a8\u66f4\u6539\u7684\u6b65\u9aa4\u4e86\uff0c\u7ed3\u5408\u4e0a\u8ff0\u4e24\u79cd\u65b9\u6cd5\u5728CD\u7684\u8fc7\u7a0b\u4e2d\u76f4\u63a5\u66ff\u6362Config\u91cc\u7684\u53d8\u91cf\u5c31\u53ef\u4ee5\u4e86\u3002\\n\\n```js title=\\"public/runtime-config.js\\"\\nwindow[config] = {\\n  clintId: \\"#{clintID}#\\"\\n}\\n```\\n\\n```html title=\\"public/index.html\\"\\n<html>\\n<head>\\n  <script src=\\"%PUBLIC_URL%/runtime-config.js\\"><\/script>\\n</head>\\n</html>\\n```\\n\\n```ts title=\\"any file\\"\\nconst clintId = process.env.NODE_ENV === \\"development\\" ? \\"xxx\\" : (window as any).config.clintId;\\n```\\n\\n\u8fd9\u6837\u5728\u672c\u5730\u5f00\u53d1\u670d\u52a1\u5668\u8fd0\u884c\u7684\u65f6\u5019\uff0c\u6211\u4eec\u83b7\u5f97\u7684clintID\u6c38\u8fdc\u662f\\"xxx\\"\uff0c\u800c\u5728\u8bbe\u7f6e\u90e8\u7f72CD\u7684\u65f6\u5019\uff0c\u6211\u4eec\u6839\u636e\u4e0d\u540c\u7684\u73af\u5883\u66ff\u6362\u6389`runtime-config.js`\u4e2d\u7684`#{clintId}#`\u5c31\u53ef\u4ee5\u4e86\u3002\\n\\n\u90e8\u7f72\u5230\u670d\u52a1\u5668\u4e4b\u540e\uff0c\u6211\u4eec\u4f1a\u53bb\u8bfb\u53d6\u4e0d\u540c\u73af\u5883\u6302\u5728window\u4e0a\u7684\u4e0d\u540c\u914d\u7f6e\u3002\\n\\n\u4e0d\u540cCD\u5de5\u5177\u6709\u4e0d\u540c\u7684\u914d\u7f6e\u65b9\u6cd5\uff0c\u4e00\u4e0b\u5df2Azure DevOps\u4e3a\u4f8b\\n\\n\u9996\u5148\u5728`Pipelines->Library`\u4e0b\u521b\u5efaVariable group\uff0c\u5e76\u5199\u5165\u5f53\u524d\u73af\u5883\u4e0b\u7684key-value\\n\\n![Library](./LibraryPipelines.png)\\n\\n\u5728Releases\u4e2d\u6784\u5efaCD\u7684\u65f6\u5019\u5f15\u7528\u8be5Group\u5230\u5f53\u524d\u90e8\u7f72\u9636\u6bb5\\n\\n![Link Variable](./link_variable.png)\\n\\n\u5728CD\u4e2d\u4f7f\u7528replace tokens\u66ff\u6362\u53d8\u91cf\\n\\n![Replace Tokens](./replace_tokens.png)"},{"id":"dynamic-height-container","metadata":{"permalink":"/blog/dynamic-height-container","source":"@site/blog/2022-03-27-dynamic-height.md","title":"CSS\u81ea\u9002\u5e94\u56fa\u5b9a\u957f\u6b3e\u6bd4\u5bb9\u5668","description":"Padding","date":"2022-03-27T00:00:00.000Z","formattedDate":"2022\u5e743\u670827\u65e5","tags":[{"label":"Front End","permalink":"/blog/tags/front-end"},{"label":"CSS","permalink":"/blog/tags/css"}],"readingTime":0.452,"truncated":false,"authors":[{"name":"Carrgan Yang","title":"Software Engineer @ Ericsson","url":"https://github.com/carrgan","imageURL":"https://carrgan.github.io/img/avantar/carrgan.jpg","key":"carrgan"}],"frontMatter":{"slug":"dynamic-height-container","title":"CSS\u81ea\u9002\u5e94\u56fa\u5b9a\u957f\u6b3e\u6bd4\u5bb9\u5668","authors":"carrgan","tags":["Front End","CSS"]},"prevItem":{"title":"\u524d\u7aef\u7684\u73af\u5883\u53d8\u91cf","permalink":"/blog/process-env-node-env"},"nextItem":{"title":"\u7528Hook\u505a\u9ad8\u7ea7\u5c01\u88c5","permalink":"/blog/react/hook/advance-encapsulation"}},"content":"## Padding\\n\\n\u5b9e\u73b0\u81ea\u9002\u5e94\u957f\u6b3e\u6bd4\u7684\u5173\u952e\u5c31\u662fpadding\uff0c\u5728\u8bbe\u7f6epadding\u7684\u65f6\u5019\u4f7f\u7528 `%` \u8ba1\u7b97\u7684\u503c\u662f\u6839\u636e\u5bbd\u5ea6\u8ba1\u7b97\u7684\uff0c\\n\\n\u4e5f\u5c31\u662f\u8bf4 `padding: 50%` \u5176\u5b9e\u662f\u57fa\u4e8e\u5bb9\u5668\u5bbd\u5ea6\u768450%\u3002\\n\\n## \u5bb9\u5668\u5b9e\u73b0\\n\\n\u6839\u636epadding\u7684\u8fd9\u4e00\u7279\u6027\u5b9e\u73b0\u8fd9\u4e00\u5bb9\u5668\u5c31\u5f88\u7b80\u5355\u4e86\\n\\n```html title=\\"16/9\u5360\u6ee1\u5c4f\u5e55\u7684\u5bb9\u5668\\"\\n<div class=\\"container\\">\\n  <div class=\\"content\\"></div>\\n</div>\\n```\\n\\n```css title=\\"16/9\u5360\u6ee1\u5c4f\u5e55\u7684\u5bb9\u5668\\"\\n.container {\\n    width: 100%;\\n    padding-bottom: 56.25%\\n}\\n.content {\\n    width: 100%;\\n    height: 100%;\\n}\\n```\\n\\n\u540c\u7406\u53ef\u5bf9\u4e00\u4e2a\u5bb9\u5668\u5b9e\u73b0\u4e00\u4e2a\u906e\u7f69\u5c42\\n\\n```html title=\\"16/9\u5360\u6ee1\u5c4f\u5e55\u7684\u80cc\u666f\u548c\u4e00\u4e2a\u60ac\u6d6e\u5c45\u4e2d\u7684\u56fe\u6807\\"\\n<div class=\\"container\\">\\n  <div class=\\"background\\"></div>\\n  <div class=\\"content\\">\\n    <svg width=\\"35px\\" height=\\"35px\\"></svg>\\n  </div>\\n</div>\\n```\\n\\n```css title=\\"16/9\u5360\u6ee1\u5c4f\u5e55\u7684\u80cc\u666f\u548c\u4e00\u4e2a\u60ac\u6d6e\u5c45\u4e2d\u7684\u56fe\u6807\\"\\n.container {\\n    width: 100%;\\n    padding-bottom: 56.25%;\\n    position: relative;\\n    top: 0;\\n    left: 0;\\n}\\n.background {\\n    width: 100%;\\n    position: absolute;\\n    top: 0;\\n    left: 0;\\n    z-index: 1;\\n}\\n.content {\\n    width: 100%;\\n    position: absolute;\\n    top: calc(50% - 35px);\\n    left: calc(50% - 35px);\\n    z-index: 2;\\n}\\n```"},{"id":"react/hook/advance-encapsulation","metadata":{"permalink":"/blog/react/hook/advance-encapsulation","source":"@site/blog/2022-03-22-React-Hook.mdx","title":"\u7528Hook\u505a\u9ad8\u7ea7\u5c01\u88c5","description":"\u5728\u4ee3\u7801\u4e2d\u6709\u5927\u91cf\u76f8\u540c\u7684\u7ec4\u4ef6\u5f15\u7528\u548c\u72b6\u6001\u5f15\u7528\u573a\u666f\u7684\u60c5\u51b5\u4e0b\uff0c\u5229\u7528\u81ea\u5b9a\u4e49Hook\u5bf9\u529f\u80fd\u8fdb\u884c\u7edf\u4e00\u5c01\u88c5\uff0c\u6709\u5229\u4e8e\u4ee3\u7801\u590d\u7528\u548c\u7ef4\u62a4\u3002","date":"2022-03-22T00:00:00.000Z","formattedDate":"2022\u5e743\u670822\u65e5","tags":[{"label":"Front End","permalink":"/blog/tags/front-end"},{"label":"React","permalink":"/blog/tags/react"}],"readingTime":8,"truncated":false,"authors":[{"name":"Carrgan Yang","title":"Software Engineer @ Ericsson","url":"https://github.com/carrgan","imageURL":"https://carrgan.github.io/img/avantar/carrgan.jpg","key":"carrgan"}],"frontMatter":{"slug":"react/hook/advance-encapsulation","title":"\u7528Hook\u505a\u9ad8\u7ea7\u5c01\u88c5","authors":"carrgan","tags":["Front End","React"],"reading_time":8},"prevItem":{"title":"CSS\u81ea\u9002\u5e94\u56fa\u5b9a\u957f\u6b3e\u6bd4\u5bb9\u5668","permalink":"/blog/dynamic-height-container"},"nextItem":{"title":"V2 Post","permalink":"/blog/v2/post"}},"content":"import Tabs from \'@theme/Tabs\';\\nimport TabItem from \'@theme/TabItem\';\\nimport CodeBlock from \\"@theme/CodeBlock\\";\\n\\n\u5728\u4ee3\u7801\u4e2d\u6709\u5927\u91cf\u76f8\u540c\u7684\u7ec4\u4ef6\u5f15\u7528\u548c\u72b6\u6001\u5f15\u7528\u573a\u666f\u7684\u60c5\u51b5\u4e0b\uff0c\u5229\u7528\u81ea\u5b9a\u4e49Hook\u5bf9\u529f\u80fd\u8fdb\u884c\u7edf\u4e00\u5c01\u88c5\uff0c\u6709\u5229\u4e8e\u4ee3\u7801\u590d\u7528\u548c\u7ef4\u62a4\u3002\\n\\n\u4f8b\u5982\u5728\u4e0d\u540c\u7684\u4e09\u4e2a\u89c6\u56fe\u4e2d\u90fd\u5b58\u5728\u8868\u683c\uff0c\u5982\u679c\u6211\u4eec\u90fd\u9700\u8981\u5bf9\u8868\u683c\u7684\u6bcf\u4e00\u5217\u6392\u5e8f\u5e76\u6784\u5efaFilter\uff0c\u5c31\u4f1a\u5b58\u5728\u5927\u91cf\u7684\u4ee3\u7801\u8026\u5408\u60c5\u51b5\u3002\\n\\n\u91c7\u7528\u4f20\u7edf\u7684\u6784\u5efa\u7ed3\u6784\u6211\u4eec\u9700\u8981\u5728\u6bcf\u4e00\u4e2a\u89c6\u56fe\u4e2d\u8bb0\u5f55\u4e00\u4e2aFilter\u72b6\u6001\u3002\\n\\n\\n<Tabs>\\n  <TabItem value=\\"ViewA\\" label=\\"View A\\" default>\\n\\n``` typescript jsx\\nconst [editedFilter, setEditedFilter] = useState<IViewADefaultFilter>(defaultFilter);\\nconst [editedSort, setEditedSort] = useState<IViewADefaultSort>(defaultSort);\\n```\\n\\n  </TabItem>\\n  <TabItem value=\\"ViewB\\" label=\\"View B\\">\\n\\n``` typescript jsx\\nconst [editedFilter, setEditedFilter] = useState<IViewBDefaultFilter>(defaultFilter);\\nconst [editedSort, setEditedSort] = useState<IViewBDefaultSort>(defaultSort);\\n```\\n\\n  </TabItem>\\n  <TabItem value=\\"ViewC\\" label=\\"View C\\">\\n\\n``` typescript jsx\\nconst [editedFilter, setEditedFilter] = useState<IViewCDefaultFilter>(defaultFilter);\\nconst [editedSort, setEditedSort] = useState<IViewCDefaultSort>(defaultSort);\\n```\\n\\n  </TabItem>\\n</Tabs>\\n\\n\u5728\u6bcf\u4e00\u4e2aView\u4e2d\uff0c\u91cd\u590d\u5bf9\u6bcf\u4e00\u5217\u5f15\u7528Filter\u7ec4\u4ef6\\n\\n<Tabs>\\n  <TabItem value=\\"ViewA\\" label=\\"View A\\" default>\\n    <CodeBlock language=\\"jsx\\" title=\\"/src/view/viewA.jsx\\">\\n      {`<>\\n  Name\\n  <InputDropdownFilter\\n      value={editedFilter.name}\\n      onValueChange={handelFilterChange(\\"name\\")}\\n      onSortChange={handelSortChange(\\"name\\")}\\n      sortStatus={editedSort.columnsA}\\n      onApply={handelFilterApply}\\n      onClean={() => setEditedFilter(f => ({ ...f, [filterKey]: \\"\\" }))}\\n  />\\n  Birthday\\n  <TimeDropdownFilter\\n    dateString={editedFilter.birthday}\\n    onValueChange={handelFilterChange(\\"birthday\\")}\\n    onSortChange={handelSortChange(\\"birthday\\")}\\n    sortStatus={editedSort.birthday}\\n    onApply={handelFilterApply}\\n    onClean={() => setEditedFilter(f => ({ ...f, [filterKey]: { from: \\"\\", to: \\"\\" } }))}\\n  />\\n</>\\n`}\\n    </CodeBlock>\\n  </TabItem>\\n  <TabItem value=\\"ViewB\\" label=\\"View B\\">\\n    <CodeBlock language=\\"jsx\\" title=\\"/src/view/viewB.jsx\\">\\n      {`<>\\n  School\\n  <InputDropdownFilter\\n      value={editedFilter.school}\\n      onValueChange={handelFilterChange(\\"school\\")}\\n      onSortChange={handelSortChange(\\"school\\")}\\n      sortStatus={editedSort.school}\\n      onApply={handelFilterApply}\\n      onClean={() => setEditedFilter(f => ({ ...f, [filterKey]: \\"\\" }))}\\n  />\\n  Teacher\\n  <ListDropdownFilter\\n      selectedItem={editedFilter.teacher}\\n      item={item}\\n      onValueChange={handelFilterChange(\\"teacher\\")}\\n      onSortChange={handelSortChange(\\"teacher\\")}\\n      sortStatus={editedSort.teacher}\\n      onApply={handelFilterApply}\\n      onClean={() => setEditedFilter(f => ({ ...f, [filterKey]: defaultFilter[filterKey] }))}\\n  />\\n</>`}\\n    </CodeBlock>\\n  </TabItem>\\n  <TabItem value=\\"ViewC\\" label=\\"View C\\">\\n    <CodeBlock language=\\"jsx\\" title=\\"/src/view/viewC.jsx\\">\\n      {`<>\\n  Onboard Day\\n  <TimeDropdownFilter\\n    dateString={editedFilter.onboardDay}\\n    onValueChange={handelFilterChange(\\"onboardDay\\")}\\n    onSortChange={handelSortChange(\\"onboardDay\\")}\\n    sortStatus={editedSort.onboardDay}\\n    onApply={handelFilterApply}\\n    onClean={() => setEditedFilter(f => ({ ...f, [filterKey]: { from: \\"\\", to: \\"\\" } }))}\\n  />\\n  Student\\n  <ListDropdownFilter\\n      selectedItem={editedFilter.student}\\n      item={item}\\n      onValueChange={handelFilterChange(\\"student\\")}\\n      onSortChange={handelSortChange(\\"student\\")}\\n      sortStatus={editedSort.student}\\n      onApply={handelFilterApply}\\n      onClean={() => setEditedFilter(f => ({ ...f, [filterKey]: defaultFilter[filterKey] }))}\\n  />\\n</>`}\\n    </CodeBlock>\\n  </TabItem>\\n</Tabs>\\n\\n\u53ef\u89c1\u5728ViewA\u3001ViewB\u3001ViewC\u4e2d\u670990%\u7684\u4ee3\u7801\u90fd\u662f\u76f8\u4f3c\u7684\uff0c\u552f\u4e00\u4e0d\u540c\u7684\u5c31\u662f\u5217\u540d\uff0c\u8fd8\u6709\u6bcf\u4e00\u5217\u7684\u987a\u5e8f\u548c\u7c7b\u578b\u3002\\n\\n\u6574\u7406\u6bcf\u4e2a\u7ec4\u4ef6\u7684\u7c7b\u578b\u540e\uff0c\u6784\u5efa\u9ad8\u7ea7Hook\u6765\u5c01\u88c5\u72b6\u6001\uff0c\u5e76\u7edf\u4e00\u66b4\u9732\u65b9\u6cd5\u3002\\n\\n<details>\\n  <summary>\u7528Hook\u7684\u5b9e\u73b0\u65b9\u5f0f</summary>\\n  <div>\\n\\n```typescript jsx title=\\"src/component/helper.tsx\\"\\nexport const useDropdownFilter = <\\n  IDefaultFilter extends { [key: string]: string | IDateString | IListBuilderItem[] },\\n  IDefaultSort extends { [key: string]: ISortStatus }\\n>(\\n  defaultFilter: IDefaultFilter,\\n  defaultSort: IDefaultSort,\\n  handelFilterApply: () => void\\n) => {\\n  const [editedFilter, setEditedFilter] = useState<IDefaultFilter>(defaultFilter);\\n  const [editedSort, setEditedSort] = useState<IDefaultSort>(defaultSort);\\n  const handelFilterChange =\\n    (name: keyof IDefaultFilter) => (value: string | IDateString | IListBuilderItem[]) => {\\n      setEditedFilter(f => ({ ...f, [name]: value }));\\n    };\\n\\n  const handelSortChange = (name: keyof IDefaultSort) => (value: ISortStatus) => {\\n    setEditedSort(f => ({ ...f, [name]: value }));\\n  };\\n\\n  const inputDropdownFilter = (\\n    filterKey: keyof IDefaultFilter,\\n    label: string,\\n    position?: \\"left\\" | \\"right\\" | undefined\\n  ) => (\\n    <>\\n      {label}\\n      <InputDropdownFilter\\n        position={position}\\n        value={editedFilter[filterKey] as string}\\n        onValueChange={handelFilterChange(filterKey)}\\n        onSortChange={handelSortChange(filterKey as keyof IDefaultSort)}\\n        sortStatus={editedSort[filterKey as keyof IDefaultSort]}\\n        onApply={handelFilterApply}\\n        onClean={() => setEditedFilter(f => ({ ...f, [filterKey]: \\"\\" }))}\\n      />\\n    </>\\n  );\\n\\n  const timeDropdownFilter = (filterKey: keyof IDefaultFilter, label: string) => (\\n    <>\\n      {label}\\n      <TimeDropdownFilter\\n        dateString={editedFilter[filterKey] as IDateString}\\n        onValueChange={handelFilterChange(filterKey)}\\n        onSortChange={handelSortChange(filterKey as keyof IDefaultSort)}\\n        sortStatus={editedSort[filterKey as keyof IDefaultSort]}\\n        onApply={handelFilterApply}\\n        onClean={() => setEditedFilter(f => ({ ...f, [filterKey]: { from: \\"\\", to: \\"\\" } }))}\\n      />\\n    </>\\n  );\\n\\n  const listDropdownFilter = (\\n    filterKey: keyof IDefaultFilter,\\n    label: string,\\n    item: IListBuilderItem[]\\n  ) => (\\n    <>\\n      {label}\\n      <ListDropdownFilter\\n        selectedItem={editedFilter[filterKey] as IListBuilderItem[]}\\n        item={item}\\n        onValueChange={handelFilterChange(filterKey)}\\n        onSortChange={handelSortChange(filterKey as keyof IDefaultSort)}\\n        sortStatus={editedSort[filterKey as keyof IDefaultSort]}\\n        onApply={handelFilterApply}\\n        onClean={() => setEditedFilter(f => ({ ...f, [filterKey]: defaultFilter[filterKey] }))}\\n      />\\n    </>\\n  );\\n\\n  return {\\n    inputDropdownFilter,\\n    timeDropdownFilter,\\n    listDropdownFilter,\\n    editedFilter,\\n    editedSort\\n  };\\n};\\n\\n```\\n\\n  </div>\\n</details>\\n\\n\\n\\n\u73b0\u5728\u5728\u6bcf\u4e00\u4e2aView\u4e2d\u53ea\u9700\u8981\u5e94\u7528\u6b21Hook\u5e76\u8c03\u7528\u5408\u9002\u7684\u65b9\u6cd5\u6e32\u67d3Filter\u5c31\u53ef\u4ee5\u4e86\\n\\n\\n\\n<Tabs>\\n  <TabItem value=\\"ViewA\\" label=\\"View A\\" default>\\n    <CodeBlock language=\\"jsx\\" title=\\"/src/view/viewA.jsx\\">\\n      {`const { editedFilter, editedSort, inputDropdownFilter, timeDropdownFilter } =\\n  useDropdownFilter(\\n    {\\n      name: \\"\\",\\n      birthday: { from: \\"\\", to: \\"\\" }\\n    },\\n    filterInit<ISorts>(Object.keys(EViewAFilterKey), undefined),\\n    handelFilterApply\\n);\\nreturn (\\n  <>\\n    {inputDropdownFilter(\\"name\\", \\"Name\\"}\\n    {timeDropdownFilter(\\"birthDay\\", \\"Name\\"}\\n  </>\\n)\\n`}\\n    </CodeBlock>\\n  </TabItem>\\n  <TabItem value=\\"ViewB\\" label=\\"View B\\">\\n    <CodeBlock language=\\"jsx\\" title=\\"/src/view/viewB.jsx\\">\\n      {`const { editedFilter, editedSort, inputDropdownFilter, listDropdownFilter } =\\n  useDropdownFilter(\\n    {\\n      school: \\"\\",\\n      teacher: teacherItems\\n    },\\n    filterInit<ISorts>(Object.keys(EViewBFilterKey), undefined),\\n    handelFilterApply\\n);\\nreturn (\\n  <>\\n    {inputDropdownFilter(\\"school\\", \\"School\\"}\\n    {listDropdownFilter(\\"teacher\\", \\"Teacher\\", teacherItems}\\n  </>\\n)\\n`}\\n    </CodeBlock>\\n  </TabItem>\\n  <TabItem value=\\"ViewC\\" label=\\"View C\\">\\n    <CodeBlock language=\\"jsx\\" title=\\"/src/view/viewC.jsx\\">\\n      {`const { editedFilter, editedSort, timeDropdownFilter, listDropdownFilter } =\\n  useDropdownFilter(\\n    {\\n      onboardDay: { from: \\"\\", to: \\"\\" },\\n      student: StudentItems\\n    },\\n    filterInit<ISorts>(Object.keys(EViewCFilterKey), undefined),\\n    handelFilterApply\\n);\\nreturn (\\n  <>\\n    {timeDropdownFilter(\\"onboardDay\\", \\"OnboardDay\\"}\\n    {listDropdownFilter(\\"student\\", \\"Student\\", StudentItems}\\n  </>\\n)\\n`}\\n    </CodeBlock>\\n  </TabItem>\\n</Tabs>\\n\\n\u51cf\u5c11\u4e86\u975e\u5e38\u591a\u7684\u4ee3\u7801\u91cf\uff0c\u4ee3\u7801\u4e5f\u66f4\u52a0\u5229\u4e8e\u8bfb\u61c2\uff0c\u7ef4\u62a4\u8d77\u6765\u4e5f\u53ea\u7528\u7ef4\u62a4hook\u5c31\u53ef\u4ee5\u4e86"},{"id":"v2/post","metadata":{"permalink":"/blog/v2/post","source":"@site/blog/2022-03-20-v2-post/index.md","title":"V2 Post","description":"\u8ddd\u79bb carrgan.io V1 \u5df2\u7ecf\u8fc7\u53bb\u5feb\u4e00\u5e74\u4e86\uff0c\u4e00\u5e74\u4e4b\u524d\u521a\u521a\u4ece\u5b66\u6821\u51fa\u6765\uff0c\u8fd8\u6ca1\u6709\u53c2\u52a0\u5de5\u4f5c\uff0c\u5229\u7528\u95f2\u6687\u65f6\u5149\u53d1\u5e03\u4e86V1\u3002","date":"2022-03-20T00:00:00.000Z","formattedDate":"2022\u5e743\u670820\u65e5","tags":[{"label":"New Version","permalink":"/blog/tags/new-version"}],"readingTime":0.836,"truncated":false,"authors":[{"name":"Carrgan Yang","title":"Software Engineer @ Ericsson","url":"https://github.com/carrgan","imageURL":"https://carrgan.github.io/img/avantar/carrgan.jpg","key":"carrgan"}],"frontMatter":{"slug":"v2/post","title":"V2 Post","authors":"carrgan","tags":["New Version"]},"prevItem":{"title":"\u7528Hook\u505a\u9ad8\u7ea7\u5c01\u88c5","permalink":"/blog/react/hook/advance-encapsulation"}},"content":"\u8ddd\u79bb carrgan.io V1 \u5df2\u7ecf\u8fc7\u53bb\u5feb\u4e00\u5e74\u4e86\uff0c\u4e00\u5e74\u4e4b\u524d\u521a\u521a\u4ece\u5b66\u6821\u51fa\u6765\uff0c\u8fd8\u6ca1\u6709\u53c2\u52a0\u5de5\u4f5c\uff0c\u5229\u7528\u95f2\u6687\u65f6\u5149\u53d1\u5e03\u4e86V1\u3002\\n\\n![v1](./V1.png)\\n\\nV1\u7528[Pmndrs](https://docs.pmnd.rs/)\u4e3aReact\u5c01\u88c5\u7684[Three.js](https://threejs.org/)\u52a0\u8f7d\u4e86\u4e00\u4e2a\u5728\u5f00\u6e90\u793e\u533a[Sketchfab](https://sketchfab.com/feed)\u627e\u7684\uff0c\u514d\u8d39\u4f7f\u7528\u76843D\u6a21\u578b\u3002\\n\\n\u7531\u4e8e\u7f51\u7ad9\u6258\u7ba1\u5728github\uff0c\u6709\u4e00\u4e9b\u7f51\u7edc\u548c\u6027\u80fd\u539f\u56e0\uff0c\u8fd8\u6709\u8fd9\u4e2a\u6a21\u578b\u4e0d\u662f\u6211\u81ea\u5df1\u5efa\u7684\uff0c\u611f\u89c9\u6709\u5f88\u591a\u9650\u5236\uff0c\u6211\u60f3\u5b9e\u73b0\u7684\u5f88\u591a\u7ec6\u8282\u529f\u80fd\uff08\u70b9\u51fb\u4e00\u4e2a3D\u7269\u4f53\uff0c\u89e6\u53d1\u6307\u5b9a\u7684\u4e8b\u4ef6\uff09\u4e0d\u80fd\u88ab\u5b9e\u73b0\uff0c\u6240\u4ee5\u653e\u5f03\u4e86\u8fd9\u4e00\u7248\u3002\\n\\n\u672c\u6765\u60f3\u8981\u81ea\u5df1\u7528[Blender](https://www.blender.org/)\u81ea\u5df1\u5efa\u4e00\u4e2a3D\u6a21\u578b\uff0c\u53ef\u662f\u8fd9\u4e2a\u8f6f\u4ef6\u5b9e\u5728\u662f\u8fc7\u4e8e\u590d\u6742\uff0c\u4e0d\u503c\u5f97\u4e3a\u4e86\u8fd9\u4e2a\u6295\u5165\u5927\u91cf\u65f6\u95f4\u53bb\u5b66\u4e60\u3002\\n\\n\u6700\u540e\u4f7f\u7528[Sketch](https://www.sketch.com)\u753b\u4e86\u4e00\u9897\u661f\u7403\u6765\u4f5c\u4e3aLogo\u548c\u4e3b\u9875\u3002\\n\\n\u5728\u5f00\u53d1V2\u7684\u65f6\u5019\u9047\u5230\u4e86\u4e00\u4e9b\u95ee\u9898\uff0c\u4e00\u5f00\u59cb\u5199\u597d\u4e4b\u540e\u53d1\u73b0Safari\u7684\u56fe\u5f62\u5904\u7406\u6027\u80fd\u5f88\u4f4e\uff0c\u7531\u4e8eSVG\u52a0\u4e86\u4e00\u4e9b\u9634\u5f71\u548c\u5149\u5f71\u6548\u679c\u5bfc\u81f4\u4e86\u6e32\u67d3\u7684\u5361\u987f\uff0c\u8feb\u4e0d\u5f97\u4e4b\u4e0b\u53ea\u80fd\u8ba9Safari\u4e0d\u6e32\u67d3\u9634\u5f71\u548c\u5149\u5f71\u3002\\n\\n\u4e4b\u540e\u4f7f\u7528`@keyframe`\u5199\u4e86\u52a8\u753b\u653e\u5728\u5168\u5c40\u7684CSS\u6587\u4ef6\u4e2d\uff0c\u7ed3\u679cDocusaurus\u6253\u5305\u7684\u65f6\u5019\u4e0d\u80fd\u6b63\u786e\u7684\u5c06`@keyframe`\u5199\u5165\u6253\u5305\u597d\u7684CSS\u6587\u4ef6\uff0c\u7531\u4e8eDocusaurus\u4f7f\u7528\u4e86[SSG](https://www.docusaurus.io/zh-CN/docs/advanced/ssg)\u6e32\u67d3\uff0c\u60f3\u8981\u624b\u52a8\u7684\u628aCSS\u5bfc\u5165\u5f88\u9ebb\u70e6\uff0c\u53ea\u80fd\u6253\u5305\u597d\u518d\u624b\u52a8\u5199\u5165`index.html`\u3002\\n\\n\u6700\u540e\u51b3\u5b9a\u9009\u7528JS\u52a8\u753b\u5e93\uff0c\u5728\u6bd4\u8f83\u4e86\u591a\u6b3eJS\u5e93\u4e4b\u540e\uff0c\u9009\u62e9\u4e86[AnimeJS](https://animejs.com)\u975e\u5e38\u5f3a\u5927\u7684JS\u5e93\uff0c\u540c\u6837\u4f7f\u7528\u4e86React\u7684\u5c01\u88c5\u7248[react-anime](https://github.com/plus1tv/react-anime/blob/HEAD/documentation.md).\\n\\n**\u5728V2.1\u7248\u672c\u4e2d\u6253\u7b97\u5904\u7406\u661f\u661f\u548c\u661f\u7403\u7684\u70b9\u51fb\u4e8b\u4ef6**"}]}')}}]);